import time
nm = NetworkManager()

def on_load_frmMain():
    lblStatus.set_panel_text(0, 'Web API Client ready')

def execute_request(method):
    url = txtUrl.caption

    if not is_valid_url(url):
        msgbox('Invalid URL', 'Error')
        return

    lblStatus.set_panel_text(0, f'Executing {method}...')
    start_time = time.time()

    try:
        if method == 'GET':
            response = nm.get(url)
        elif method == 'POST':
            body = txtBody.caption
            try:
                data = json.loads(body)
                response = nm.post(url, data)
            except:
                response = nm.post(url, body)
        else:
            response = nm.get(url)

        elapsed = int((time.time() - start_time) * 1000)

        # Display response
        if response.is_success():
            if response.body:
                try:
                    # Try to pretty print JSON
                    parsed = json.loads(response.body)
                    txtResponse.caption = json.dumps(parsed, indent=2)
                except:
                    txtResponse.caption = response.body
            else:
                txtResponse.caption = '(Empty response)'

            lblStatus.set_panel_text(0, f'{method} successful')
            lblStatus.set_panel_text(1, f'Status: {response.status_code}')
            lblStatus.set_panel_text(2, f'Time: {elapsed}ms')
        else:
            txtResponse.caption = f'Error {response.status_code}:\n{response.body}'
            lblStatus.set_panel_text(0, 'Request failed')
            lblStatus.set_panel_text(1, f'Status: {response.status_code}')

    except Exception as e:
        txtResponse.caption = f'Exception: {str(e)}'
        lblStatus.set_panel_text(0, 'Error')
        lblStatus.set_panel_text(1, 'Status: ERR')

def on_menu_mnuGet():
    execute_request('GET')

def on_menu_mnuPost():
    execute_request('POST')

def on_menu_mnuClear():
    txtResponse.caption = ''
    lblStatus.set_panel_text(0, 'Cleared')
    lblStatus.set_panel_text(1, 'Ready')
    lblStatus.set_panel_text(2, 'Time: --ms')

def on_menu_mnuFormat():
    try:
        text = txtResponse.caption
        if text:
            parsed = json.loads(text)
            txtResponse.caption = json.dumps(parsed, indent=2)
            lblStatus.set_panel_text(0, 'JSON formatted')
    except:
        msgbox('Invalid JSON in response', 'Format')

def on_menu_mnuValidate():
    url = txtUrl.caption
    if is_valid_url(url):
        msgbox(f'URL is valid:\n{url}', 'Validate')
    else:
        msgbox(f'URL is invalid:\n{url}', 'Validate')

def on_menu_mnuJsonPlaceholder():
